## 4. 도메인 3: 매칭/소셜

### JPA Entity

파일 위치: `domain/src/main/kotlin/com/maum/backend/entity/social/`

```kotlin
// LikeEntity.kt
@Entity
@Table(
    catalog = "maum",
    name = "like",
    uniqueConstraints = [UniqueConstraint(columnNames = ["from_user_id", "to_user_id"])]
)
@EntityListeners(AuditingEntityListener::class)
class LikeEntity(
    @Id
    @GeneratedValue(generator = "uuid2")
    @GenericGenerator(name = "uuid2", strategy = "uuid2")
    val id: String = "",

    val fromUserId: String,                       // 좋아요 보낸 유저
    val toUserId: String,                         // 좋아요 받은 유저

    @CreatedDate
    @Column(columnDefinition = "datetime(3)", nullable = false, updatable = false)
    var createdAt: LocalDateTime = LocalDateTime.now(),
)
```

```kotlin
// MatchEntity.kt
@Entity
@Table(catalog = "maum", name = "match")
@EntityListeners(AuditingEntityListener::class)
class MatchEntity(
    @Id
    @GeneratedValue(generator = "uuid2")
    @GenericGenerator(name = "uuid2", strategy = "uuid2")
    val id: String = "",

    val userAId: String,                          // 매칭 유저 A (정렬: A < B)
    val userBId: String,                          // 매칭 유저 B

    @Enumerated(EnumType.STRING)
    var matchStatus: MatchStatus = MatchStatus.ACTIVE,

    var matchedAt: LocalDateTime = LocalDateTime.now(),

    @CreatedDate
    @Column(columnDefinition = "datetime(3)", nullable = false, updatable = false)
    var createdAt: LocalDateTime = LocalDateTime.now(),

    @LastModifiedDate
    var updatedAt: LocalDateTime = LocalDateTime.now(),
)

enum class MatchStatus { ACTIVE, UNMATCHED }
```

```kotlin
// FollowEntity.kt
@Entity
@Table(
    catalog = "maum",
    name = "follow",
    uniqueConstraints = [UniqueConstraint(columnNames = ["follower_id", "following_id"])]
)
@EntityListeners(AuditingEntityListener::class)
class FollowEntity(
    @Id
    @GeneratedValue(generator = "uuid2")
    @GenericGenerator(name = "uuid2", strategy = "uuid2")
    val id: String = "",

    val followerId: String,                       // 팔로우하는 유저
    val followingId: String,                      // 팔로우받는 유저

    @CreatedDate
    @Column(columnDefinition = "datetime(3)", nullable = false, updatable = false)
    var createdAt: LocalDateTime = LocalDateTime.now(),
)
```

```kotlin
// BlockEntity.kt
@Entity
@Table(
    catalog = "maum",
    name = "block",
    uniqueConstraints = [UniqueConstraint(columnNames = ["blocker_id", "blocked_id"])]
)
@EntityListeners(AuditingEntityListener::class)
class BlockEntity(
    @Id
    @GeneratedValue(generator = "uuid2")
    @GenericGenerator(name = "uuid2", strategy = "uuid2")
    val id: String = "",

    val blockerId: String,                        // 차단한 유저
    val blockedId: String,                        // 차단당한 유저
    var reason: String? = null,

    @CreatedDate
    @Column(columnDefinition = "datetime(3)", nullable = false, updatable = false)
    var createdAt: LocalDateTime = LocalDateTime.now(),
)
```

### 인덱스 전략

```sql
-- like 테이블
CREATE UNIQUE INDEX uq_like_from_to ON maum.like (from_user_id, to_user_id);
CREATE INDEX idx_like_to_user ON maum.like (to_user_id, created_at);   -- 받은 좋아요 조회

-- match 테이블
CREATE UNIQUE INDEX uq_match_users ON maum.match (user_a_id, user_b_id);
CREATE INDEX idx_match_user_a ON maum.match (user_a_id, match_status);
CREATE INDEX idx_match_user_b ON maum.match (user_b_id, match_status);

-- follow 테이블
CREATE UNIQUE INDEX uq_follow ON maum.follow (follower_id, following_id);
CREATE INDEX idx_follow_follower ON maum.follow (follower_id, created_at);
CREATE INDEX idx_follow_following ON maum.follow (following_id, created_at);

-- block 테이블
CREATE UNIQUE INDEX uq_block ON maum.block (blocker_id, blocked_id);
CREATE INDEX idx_block_blocker ON maum.block (blocker_id);
```

### GraphQL 스키마

파일 위치: `graphql/src/main/resources/graphql/social.graphqls`

```graphql
type Like {
    id: ID!
    fromUserId: ID!
    toUserId: ID!
    fromUser: SimpleUser
    createdAt: String!
}

type Match {
    id: ID!
    userAId: ID!
    userBId: ID!
    matchStatus: String!
    matchedAt: String!
    partner: SimpleUser
}

type Follow {
    id: ID!
    followerId: ID!
    followingId: ID!
    user: SimpleUser
    createdAt: String!
}

extend type Query {
    myLikes(limit: Int, offset: Int): [Like!]!
    likesReceived(limit: Int, offset: Int): [Like!]!
    myMatches(limit: Int, offset: Int): [Match!]!
    myFollowers(limit: Int, offset: Int): [Follow!]!
    myFollowings(limit: Int, offset: Int): [Follow!]!
    isBlocked(targetUserId: ID!): Boolean!
}

extend type Mutation {
    likeUser(targetUserId: ID!): Like!
    unlikeUser(targetUserId: ID!): Boolean!
    followUser(targetUserId: ID!): Follow!
    unfollowUser(targetUserId: ID!): Boolean!
    blockUser(targetUserId: ID!, reason: String): Boolean!
    unblockUser(targetUserId: ID!): Boolean!
}
```

### gRPC Proto

파일 위치: `protobuf/src/main/proto/social/social_service.proto`

```protobuf
syntax = "proto3";
package social;

option java_multiple_files = true;
option java_package = "com.maum.backend.protobuf.social";

service SocialService {
  rpc LikeUser(LikeUserRequest) returns (LikeUserResponse);
  rpc UnlikeUser(UnlikeUserRequest) returns (UnlikeUserResponse);
  rpc ListMyLikes(ListMyLikesRequest) returns (ListMyLikesResponse);
  rpc ListLikesReceived(ListLikesReceivedRequest) returns (ListLikesReceivedResponse);
  rpc ListMyMatches(ListMyMatchesRequest) returns (ListMyMatchesResponse);
  rpc FollowUser(FollowUserRequest) returns (FollowUserResponse);
  rpc UnfollowUser(UnfollowUserRequest) returns (UnfollowUserResponse);
  rpc BlockUser(BlockUserRequest) returns (BlockUserResponse);
  rpc UnblockUser(UnblockUserRequest) returns (UnblockUserResponse);
  rpc IsBlocked(IsBlockedRequest) returns (IsBlockedResponse);
}

message LikeProto {
  string id = 1;
  string from_user_id = 2;
  string to_user_id = 3;
  string created_at = 4;
}

message MatchProto {
  string id = 1;
  string user_a_id = 2;
  string user_b_id = 3;
  string match_status = 4;
  string matched_at = 5;
}

message FollowProto {
  string id = 1;
  string follower_id = 2;
  string following_id = 3;
  string created_at = 4;
}

message LikeUserRequest {
  string from_user_id = 1;
  string to_user_id = 2;
}

